mapper.select:
    	/* com.erns.coching.common.file.mapper.PdfInfoDAO.getList */

			SELECT

			FROM T_PDF_INFO AA





				OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.common.file.mapper.PdfInfoDAO.getListCount */
SELECT COUNT(*) FROM T_PDF_INFO AA
AND AA.DEL_YN = 'N'

    	/* com.erns.coching.common.file.mapper.PdfInfoDAO.load */

			SELECT

			FROM T_PDF_INFO AA

				AND AA.FILE_ID = #{fileId , jdbcType=VARCHAR}

			LIMIT 1

    	/* com.erns.coching.common.file.mapper.PdfInfoDAO.loadVo */

			SELECT

			FROM T_PDF_INFO AA

				AND AA.FILE_ID = #{fileId , jdbcType=VARCHAR}

			LIMIT 1

mapper.insert:
    	/* com.erns.coching.common.file.mapper.PdfInfoDAO.insert */

    	INSERT INTO T_PDF_INFO (
						FILE_ID
					, FILE_NAME
					, FILE_EXT
					, FILE_NAME_DEST
					, FILE_PATH
					, FILE_SIZE
					, RGT_DTTM

					, PAGE_COUNT
					, PAGE_IMG_PATH
					, CONTENT	
					, CONTENT_DTTM					
				) VALUES (
						#{fileId		, jdbcType=VARCHAR}
					, #{fileName	, jdbcType=VARCHAR}
					, #{fileExt		, jdbcType=VARCHAR}
					, #{fileNameDest, jdbcType=VARCHAR}
					, #{filePath	, jdbcType=VARCHAR}
					, #{fileSize	, jdbcType=INTEGER}
					, now()

					, #{pageCount	, jdbcType=INTEGER}
					, #{pageImgPath, jdbcType=VARCHAR}
					, #{content	, jdbcType=VARCHAR}
					, (CASE 
							WHEN #{content	, jdbcType=VARCHAR} IS NOT NULL THEN now()
							ELSE NULL
						END ) 
				)
